import{_ as o,o as a,c as r,ai as s}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"API 用量与费用","description":"","frontmatter":{"read_when":["你想了解哪些功能可能调用付费 API","你需要审核密钥、费用和用量可见性","你正在解释 /status 或 /usage 的费用报告"],"summary":"审核哪些功能会产生费用、使用了哪些密钥以及如何查看用量","title":"API 用量与费用","x-i18n":{"generated_at":"2026-02-01T21:37:08Z","model":"claude-opus-4-5","provider":"pi","source_hash":"807d0d88801e919a8246517820644db1e6271d165fa376b2e637f05a9121d8b1","source_path":"reference/api-usage-costs.md","workflow":15}},"headers":[],"relativePath":"zh-CN/reference/api-usage-costs.md","filePath":"zh-CN/reference/api-usage-costs.md","lastUpdated":null}'),l={name:"zh-CN/reference/api-usage-costs.md"};function c(t,e,d,i,n,p){return a(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="api-用量与费用" tabindex="-1"><a class="header-anchor" href="#api-用量与费用">#</a> API 用量与费用</h1><p>本文档列出了<strong>可能调用 API 密钥的功能</strong>及其费用的显示位置。重点介绍 OpenSoul 中可能产生提供商用量或付费 API 调用的功能。</p><h2 id="费用显示位置-聊天-cli" tabindex="-1"><a class="header-anchor" href="#费用显示位置-聊天-cli">#</a> 费用显示位置（聊天 + CLI）</h2><p><strong>每会话费用快照</strong></p><ul><li><code>/status</code> 显示当前会话模型、上下文用量和上次响应的 token 数。</li><li>如果模型使用 <strong>API 密钥认证</strong>，<code>/status</code> 还会显示上次回复的<strong>预估费用</strong>。</li></ul><p><strong>每条消息费用页脚</strong></p><ul><li><code>/usage full</code> 在每条回复后附加用量页脚，包括<strong>预估费用</strong>（仅限 API 密钥）。</li><li><code>/usage tokens</code> 仅显示 token 数；OAuth 流程会隐藏美元费用。</li></ul><p><strong>CLI 用量窗口（提供商配额）</strong></p><ul><li><code>opensoul status --usage</code> 和 <code>opensoul channels list</code> 显示提供商<strong>用量窗口</strong>（配额快照，非每条消息的费用）。</li></ul><p>详情和示例请参阅 <a href="/docs/reference/token-use">Token 用量与费用</a>。</p><h2 id="密钥的发现方式" tabindex="-1"><a class="header-anchor" href="#密钥的发现方式">#</a> 密钥的发现方式</h2><p>OpenSoul 可以从以下来源获取凭据：</p><ul><li><strong>认证配置文件</strong>（按智能体配置，存储在 <code>auth-profiles.json</code> 中）。</li><li><strong>环境变量</strong>（例如 <code>OPENAI_API_KEY</code>、<code>BRAVE_API_KEY</code>、<code>FIRECRAWL_API_KEY</code>）。</li><li><strong>配置文件</strong>（<code>models.providers.*.apiKey</code>、<code>tools.web.search.*</code>、<code>tools.web.fetch.firecrawl.*</code>、<code>memorySearch.*</code>、<code>talk.apiKey</code>）。</li><li><strong>Skills</strong>（<code>skills.entries.&lt;name&gt;.apiKey</code>），可能会将密钥导出到 Skills 进程的环境变量中。</li></ul><h2 id="可能消耗密钥的功能" tabindex="-1"><a class="header-anchor" href="#可能消耗密钥的功能">#</a> 可能消耗密钥的功能</h2><h3 id="_1-核心模型响应-聊天-工具" tabindex="-1"><a class="header-anchor" href="#_1-核心模型响应-聊天-工具">#</a> 1）核心模型响应（聊天 + 工具）</h3><p>每次回复或工具调用都使用<strong>当前模型提供商</strong>（OpenAI、Anthropic 等）。这是用量和费用的主要来源。</p><p>定价配置请参阅<a href="/docs/providers/models">模型</a>，显示方式请参阅 <a href="/docs/reference/token-use">Token 用量与费用</a>。</p><h3 id="_2-媒体理解-音频-图像-视频" tabindex="-1"><a class="header-anchor" href="#_2-媒体理解-音频-图像-视频">#</a> 2）媒体理解（音频/图像/视频）</h3><p>入站媒体可以在回复生成前进行摘要/转录。这会使用模型/提供商 API。</p><ul><li>音频：OpenAI / Groq / Deepgram（当密钥存在时<strong>自动启用</strong>）。</li><li>图像：OpenAI / Anthropic / Google。</li><li>视频：Google。</li></ul><p>请参阅<a href="/docs/nodes/media-understanding">媒体理解</a>。</p><h3 id="_3-记忆嵌入-语义搜索" tabindex="-1"><a class="header-anchor" href="#_3-记忆嵌入-语义搜索">#</a> 3）记忆嵌入 + 语义搜索</h3><p>语义记忆搜索在配置为远程提供商时使用<strong>嵌入 API</strong>：</p><ul><li><code>memorySearch.provider = &quot;openai&quot;</code> → OpenAI 嵌入</li><li><code>memorySearch.provider = &quot;gemini&quot;</code> → Gemini 嵌入</li><li>本地嵌入失败时可选回退到 OpenAI</li></ul><p>你可以使用 <code>memorySearch.provider = &quot;local&quot;</code> 保持本地运行（无 API 用量）。</p><p>请参阅<a href="/docs/concepts/memory">记忆</a>。</p><h3 id="_4-网页搜索工具-brave-通过-openrouter-使用-perplexity" tabindex="-1"><a class="header-anchor" href="#_4-网页搜索工具-brave-通过-openrouter-使用-perplexity">#</a> 4）网页搜索工具（Brave / 通过 OpenRouter 使用 Perplexity）</h3><p><code>web_search</code> 使用 API 密钥，可能产生使用费用：</p><ul><li><strong>Brave Search API</strong>：<code>BRAVE_API_KEY</code> 或 <code>tools.web.search.apiKey</code></li><li><strong>Perplexity</strong>（通过 OpenRouter）：<code>PERPLEXITY_API_KEY</code> 或 <code>OPENROUTER_API_KEY</code></li></ul><p><strong>Brave 免费套餐（额度充裕）：</strong></p><ul><li><strong>每月 2,000 次请求</strong></li><li><strong>每秒 1 次请求</strong></li><li><strong>需要信用卡</strong>进行验证（除非升级否则不会收费）</li></ul><p>请参阅<a href="/docs/tools/web">网页工具</a>。</p><h3 id="_5-网页抓取工具-firecrawl" tabindex="-1"><a class="header-anchor" href="#_5-网页抓取工具-firecrawl">#</a> 5）网页抓取工具（Firecrawl）</h3><p><code>web_fetch</code> 在存在 API 密钥时可以调用 <strong>Firecrawl</strong>：</p><ul><li><code>FIRECRAWL_API_KEY</code> 或 <code>tools.web.fetch.firecrawl.apiKey</code></li></ul><p>如果未配置 Firecrawl，该工具会回退到直接抓取 + 可读性提取（无付费 API）。</p><p>请参阅<a href="/docs/tools/web">网页工具</a>。</p><h3 id="_6-提供商用量快照-状态-健康检查" tabindex="-1"><a class="header-anchor" href="#_6-提供商用量快照-状态-健康检查">#</a> 6）提供商用量快照（状态/健康检查）</h3><p>某些状态命令会调用<strong>提供商用量端点</strong>以显示配额窗口或认证健康状态。这些通常是低频调用，但仍会访问提供商 API：</p><ul><li><code>opensoul status --usage</code></li><li><code>opensoul models status --json</code></li></ul><p>请参阅<a href="/docs/cli/models">模型 CLI</a>。</p><h3 id="_7-压缩保护摘要" tabindex="-1"><a class="header-anchor" href="#_7-压缩保护摘要">#</a> 7）压缩保护摘要</h3><p>压缩保护功能可以使用<strong>当前模型</strong>对会话历史进行摘要，运行时会调用提供商 API。</p><p>请参阅<a href="/docs/reference/session-management-compaction">会话管理 + 压缩</a>。</p><h3 id="_8-模型扫描-探测" tabindex="-1"><a class="header-anchor" href="#_8-模型扫描-探测">#</a> 8）模型扫描/探测</h3><p><code>opensoul models scan</code> 可以探测 OpenRouter 模型，启用探测时会使用 <code>OPENROUTER_API_KEY</code>。</p><p>请参阅<a href="/docs/cli/models">模型 CLI</a>。</p><h3 id="_9-语音对话-talk" tabindex="-1"><a class="header-anchor" href="#_9-语音对话-talk">#</a> 9）语音对话（Talk）</h3><p>语音对话模式在配置后可以调用 <strong>ElevenLabs</strong>：</p><ul><li><code>ELEVENLABS_API_KEY</code> 或 <code>talk.apiKey</code></li></ul><p>请参阅<a href="/docs/nodes/talk">语音对话模式</a>。</p><h3 id="_10-skills-第三方-api" tabindex="-1"><a class="header-anchor" href="#_10-skills-第三方-api">#</a> 10）Skills（第三方 API）</h3><p>Skills 可以在 <code>skills.entries.&lt;name&gt;.apiKey</code> 中存储 <code>apiKey</code>。如果 Skills 使用该密钥调用外部 API，则会根据 Skills 的提供商产生费用。</p><p>请参阅<a href="/docs/tools/skills">Skills</a>。</p>',54)])])}const g=o(l,[["render",c]]);export{u as __pageData,g as default};
